    async function renderExperience(){$("v16Main").innerHTML=`${page("PERSONAL CREATOR EXPERIENCE","Make Worldsmith yours","Choose how much guidance you want, then tune motion, contrast, text size, sound, controller support, and workspace density.",`<button data-v16-action="experience-save" class="v16-primary">Apply experience</button>`)}<section class="v16-experience"><div class="v16-mode-cards">${[["beginner","LEARN","Beginner","Step-by-step journeys and plain-language controls."],["guided","CREATE","Guided","Recommended actions with advanced tools nearby."],["expert","MASTER","Expert","Dense workspaces, shortcuts, and minimal coaching."]].map(([id,kicker,title,text])=>`<button data-v16-mode="${id}" class="${state.mode===id?"active":""}"><small>${kicker}</small><i>${id==="beginner"?"☀":id==="guided"?"✦":"◆"}</i><strong>${title}</strong><span>${text}</span><b>${state.mode===id?"SELECTED":"CHOOSE"}</b></button>`).join("")}</div><div class="v16-settings"><section><small>ACCESSIBILITY</small>${[["highContrast","High contrast","Strengthen edges and status colors"],["largeText","Large text","Increase reading size throughout Worldsmith"],["reducedMotion","Reduced motion","Replace movement with simple fades"]].map(([key,title,text])=>`<label><span><strong>${title}</strong><small>${text}</small></span><input data-v16-setting="${key}" type="checkbox"${state[key]?" checked":""}><i></i></label>`).join("")}</section><section><small>FEEDBACK & CONTROL</small>${[["sound","Interface sounds","Gentle navigation and confirmation tones"],["controller","Controller navigation","Spatial focus, shoulder tabs, and face buttons"]].map(([key,title,text])=>`<label><span><strong>${title}</strong><small>${text}</small></span><input data-v16-setting="${key}" type="checkbox"${state[key]?" checked":""}><i></i></label>`).join("")}</section></div><aside><small>LIVE PREVIEW</small><div class="v16-preview-card"><i>✦</i><span><strong>Your next recommended action</strong><small>Paint the opening map, then validate its passage routes.</small></span><button>Continue</button></div><p>Worldsmith’s visual identity is original and independent. It aims for approachable console-quality interaction without copying another company’s branding or assets.</p></aside></section>`;document.querySelectorAll("[data-v16-mode]").forEach(button=>button.onclick=()=>{state.mode=button.dataset.v16Mode;persist();renderExperience();});document.querySelectorAll("[data-v16-setting]").forEach(input=>input.onchange=()=>{state[input.dataset.v16Setting]=input.checked;applyExperience();persist();});}
    function applyExperience(){document.documentElement.classList.toggle("v16-high-contrast",!!state.highContrast);document.documentElement.classList.toggle("v16-large-text",!!state.largeText);document.documentElement.classList.toggle("v16-reduced-motion",!!state.reducedMotion);document.documentElement.dataset.v16Mode=state.mode;}
